INSERT INTO `visits` VALUES (30001,30001,60002,'2026-04-15 19:39:47','Fine',NULL,NULL,'2026-04-15 19:39:46'),(60001,60001,60002,'2026-04-16 18:42:47',NULL,NULL,NULL,'2026-04-16 18:42:46'),(90001,120001,600001,'2026-04-17 06:35:05','Dinsdag gekuier',NULL,NULL,'2026-04-17 06:35:05'),(120001,30001,120011,'2026-04-19 12:26:59','Ouma het baie stories vertel en haar verstand is nog so helder!\nOns is bederf met lekker koffie en soet goed!',NULL,5,'2026-04-19 12:26:58'),(150001,60001,420156,'2026-04-20 14:10:36','Dit gaan goed vandag. Ouma sê sy was op memory lane na Maranatha Park. Sy het glad nie vir die prediker geluister nie maar net na die mooi man hier langs haar geloer. Sy profiel was vir haar so mooi… 😂😂 Ag jinne kan julle glo…!!',NULL,NULL,'2026-04-20 14:10:35'),(180001,150001,60002,'2026-04-20 19:33:46','Quick',NULL,NULL,'2026-04-20 19:33:45'),(210001,60001,990001,'2026-04-23 12:42:04',NULL,NULL,NULL,'2026-04-23 12:42:03'),(240001,180001,2220001,'2026-04-24 17:42:32',NULL,NULL,NULL,'2026-04-24 17:42:31'),(270001,210001,2490001,'2026-04-29 12:40:19','Ek het haar vandag gebel',NULL,NULL,'2026-04-29 12:40:19'),(300001,180001,2520007,'2026-04-29 14:42:31','94 Birthday visit!',NULL,NULL,'2026-04-29 14:42:30'),(330001,30001,2730001,'2026-05-03 13:01:43',NULL,NULL,5,'2026-05-03 13:01:43'),(360001,30001,2910004,'2026-05-09 07:15:25','Called gran and spoke about my life and work. More of a quick catchup. ',NULL,5,'2026-05-09 07:15:24'),(390001,150001,60002,'2026-05-15 10:36:47',NULL,NULL,NULL,'2026-05-15 10:36:46'),(420001,30001,60002,'2026-05-17 16:39:27','Sy geniet die party :) Dankie reëlings',NULL,4,'2026-05-17 16:39:27'),(450001,30001,2910004,'2026-05-19 15:11:41','Ouma verjaar, was \'n lekker gesels',NULL,5,'2026-05-19 15:11:41');
